import { Integer } from '../asn1/Integer.js';
import { asn1js, PkiBase } from '../core/PkiBase.js';
import { GeneralName, GeneralNames } from './GeneralName.js';
import { Name } from './Name.js';
import { Asn1ParseError } from '../core/errors/Asn1ParseError.js';
/**
 * Represents the ASN.1 IssuerSerial structure.
 *
 * @asn
 * ```asn
 * IssuerSerial ::= SEQUENCE {
 *      issuer GeneralNames,
 *      serialNumber CertificateSerialNumber
 * }
 *
 * CertificateSerialNumber ::= INTEGER
 * ```
 */
export class IssuerSerial extends PkiBase {
    issuer;
    serialNumber;
    constructor(options) {
        super();
        this.issuer =
            options.issuer instanceof Name.RDNSequence
                ? new GeneralNames(GeneralName.directoryName.fromName(options.issuer))
                : options.issuer;
        this.serialNumber = options.serialNumber;
    }
    toAsn1() {
        return new asn1js.Sequence({
            value: [this.issuer.toAsn1(), this.serialNumber.toAsn1()],
        });
    }
    static fromAsn1(asn1) {
        if (!(asn1 instanceof asn1js.Sequence)) {
            throw new Asn1ParseError('Invalid ASN.1 structure: expected SEQUENCE');
        }
        const sequence = asn1;
        if (sequence.valueBlock.value.length !== 2) {
            throw new Asn1ParseError('Invalid ASN.1 structure: expected 2 elements in SEQUENCE');
        }
        const issuer = GeneralNames.fromAsn1(sequence.valueBlock.value[0]);
        const serialNumber = Integer.fromAsn1(sequence.valueBlock.value[1]);
        return new IssuerSerial({ issuer, serialNumber });
    }
}
